// pathName extracts the simple name from a memefish Path (last identifier).
func pathName(p *ast.Path) string {
	if p == nil || len(p.Idents) == 0 {
		return ""
	}
	return p.Idents[len(p.Idents)-1].Name
}

func columnHasTrueOption(options *ast.Options, name string) bool {
	if options == nil {
		return false
	}
	for _, record := range options.Records {
		if record.Name.Name != name {
			continue
		}
		lit, ok := record.Value.(*ast.BoolLiteral)
		return ok && lit.Value
	}
	return false
}

func fieldWriteSemanticsFromDefaultSemantics(semantics ast.ColumnDefaultSemantics) (hasDefault, isGenerated bool) {
	switch semantics.(type) {
	case nil:
		return false, false
	case *ast.GeneratedColumnExpr:
		return false, true
	default:
		return true, false
	}
}

func fieldWriteSemanticsFromInformationSchema(columnDefault, generationExpression spanner.NullString) (hasDefault, isGenerated bool) {
	if generationExpression.Valid && strings.TrimSpace(generationExpression.StringVal) != "" {
		return false, true
	}
	return columnDefault.Valid && strings.TrimSpace(columnDefault.StringVal) != "", false
}

// snakeToCamel converts a snake_case string to CamelCase.
func snakeToCamel(s string) string {
	return upperCamelIdentifier(s)
}

